// TCP Slow Start
cwnd = 1 // Initial cwnd in MSS
ssthresh = 65535 // Initial ssthresh in bytes

FUNCTION onACK(ack):
 IF cwnd < ssthresh:
 // Slow Start: exponential increase
 cwnd = cwnd + 1 // For each ACK, increase by 1 MSS
 ELSE:
 // Congestion Avoidance: linear increase
 cwnd = cwnd + (1/cwnd) // Increase by 1/cwnd per ACK

FUNCTION onTimeout():
 // Timeout indicates severe congestion
 ssthresh = cwnd / 2
 cwnd = 1 // Reset to start
